interface IAccountSupportProfile extends Pick<Account, 'email' | 'phone' | 'softDescriptor'> {
  city: string;
  country: string;
  line1: string;
  line2: string;
  postalCode: string;
  region: string;
  social: {
    provider: SocialProvider;
    url: string;
  }[];
}

type SupportProfileAddressPayload = AddressAttributes & {
  accountId?: string;
  addressType: AddressType;
  id?: string;
};

type AddressReviewState = {
  account: IAccountSupportProfile;
  address: SupportProfileAddressPayload;
  suggestedAddress: SmartySuggestedAddress;
};

export function SupportProfile() {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'supportProfile' });
  const { t: tCommon } = useTranslation('common');
  const { showToast } = useToast();

  const { navigateNextStep } = useSteps();

  const { isLoading: verifyAddressIsLoading, verifyAddress } = useVerifySmartyAddress();
  const [addressReviewState, setAddressReviewState] = useState<AddressReviewState | null>(null);
  const [undeliverableAddressState, setUndeliverableAddressState] = useState<{
    account: IAccountSupportProfile;
    address: SupportProfileAddressPayload;
  } | null>(null);

  const { currentAccount, isLoading } = useGetAccount();
  const { data: accounts } = useGetAccounts({
    perPage: 1,
    status: 'active',
    userId: currentAccount?.id,
  });
  const activeAccount = accounts?.[0];
  const accountSlug = activeAccount?.slug ?? currentAccount?.slug;

  const { isLoading: updateAccountIsLoading, updateAccount } = useUpdateAccount({
    shouldShowToast: false,
  });

  const { addresses, isLoading: addressIsLoading } = useGetAddresses({
    accountId: currentAccount?.id,
    options: {
      types: ['other'],
    },
  });

  const { createAddress, createAddressIsLoading } = useCreateAddress({ shouldShowToast: false });
  const { updateAddress, updateAddressIsLoading } = useUpdateAddress({ shouldShowToast: false });

  const existingAddress = addresses[0];

  if (isLoading || addressIsLoading) {
    return <Loading />;
  }

  const buildAddressPayload = (account: IAccountSupportProfile): SupportProfileAddressPayload => ({
    accountId: currentAccount?.id,
    addressType: 'other',
    city: account.city,
    country: account.country,
    id: existingAddress?.id,
    line1: account.line1,
    line2: account.line2,
    postalCode: account.postalCode,
    region: account.region,
  });

  const persistSupportProfile = (
    accountValues: IAccountSupportProfile,
    addressValues: SupportProfileAddressPayload
  ) => {
    const newAccount = {
      email: accountValues.email,
      facebook: getSocialUrlValue(accountValues.social, SocialProvider.Facebook),
      instagram: getSocialUrlValue(accountValues.social, SocialProvider.Instagram),
      rumble: getSocialUrlValue(accountValues.social, SocialProvider.Rumble),
      phone: accountValues.phone,
      softDescriptor: accountValues.softDescriptor,
      twitter: getSocialUrlValue(accountValues.social, SocialProvider.Twitter),
      url: getSocialUrlValue(accountValues.social, SocialProvider.Website),
    };

    const addressFunction = existingAddress ? updateAddress : createAddress;

    const onError = () => {
      showToast({
        message: t('requests.onError'),
        variant: 'error',
      });
    };

    updateAccount(
      { updates: newAccount },
      {
        onError,
        onSuccess: () => {
          addressFunction(addressValues, {
            onError,
            onSuccess: () => navigateNextStep(),
          });
        },
      }
    );
  };

  const handleAddressSelection = (useSuggested: boolean) => {
    if (!addressReviewState) {
      return;
    }

    const selectedAddress = useSuggested
      ? mergeSuggestedAddress(addressReviewState.address, addressReviewState.suggestedAddress)
      : addressReviewState.address;

    // We send the entire smarty response in the metadata so that we
    //   don't need to hit the smarty api on the backend or later for
    //   things like lat/long etc.
    selectedAddress.metadata = addressReviewState.suggestedAddress;

    setAddressReviewState(null);
    persistSupportProfile(addressReviewState.account, selectedAddress);
  };

  const handleKeepEnteredAddress = () => handleAddressSelection(false);
  const handleUseSuggestedAddress = () => handleAddressSelection(true);
  const handleCloseUndeliverableModal = () => setUndeliverableAddressState(null);

  const handleConfirmUndeliverableAddress = () => {
    if (!undeliverableAddressState) {
      return;
    }

    const { account, address } = undeliverableAddressState;
    setUndeliverableAddressState(null);
    persistSupportProfile(account, address);
  };

  const onSubmit = async (account: IAccountSupportProfile) => {
    const addressPayload = buildAddressPayload(account);

    try {
      const suggestions = await verifyAddress({
        accountSlug,
        address: toSmartyAddress(addressPayload),
      });
      const suggestedAddress = suggestions?.[0];

      if (suggestionIsDifferent(addressPayload, suggestedAddress) && suggestedAddress) {
        setAddressReviewState({
          account,
          address: addressPayload,
          suggestedAddress,
        });
        return;
      }

      if (suggestedAddress?.analysis?.dpv_match_code.toLowerCase() === 'n') {
        setUndeliverableAddressState({
          account,
          address: addressPayload,
        });
        return;
      }
    } catch (err) {
      // NOTE: This breaks i18n but we should never hit this as the frontend
      // validation should mirror the backend validation.
      const errorDetails = getErrorDetails(err);
      const message = errorDetails.length
        ? errorDetails.join('\n')
        : t('addressVerification.error');
      showToast({
        message,
        variant: 'error',
      });
    }

    persistSupportProfile(account, addressPayload);
  };

  const suggestedAddressPreview = addressReviewState
    ? mergeSuggestedAddress(addressReviewState.address, addressReviewState.suggestedAddress)
    : null;

  const enteredAddressLines = addressReviewState
    ? formatAddressLines(addressReviewState.address)
    : [];
  const suggestedAddressLines = suggestedAddressPreview
    ? formatAddressLines(suggestedAddressPreview)
    : [];
