import { TFunction } from 'react-i18next';
import * as yup from 'yup';

// tests for valid https urls
//  www is optional
//  domain
//  tld
//  any query params
//  valid examples: https://www.google.com/search?q=test
//                  https://google.com
const HTTPS_URL_REGEX =
  /https:\/\/(www\.)?[-a-zA-Z0-9@:%._+~#=]{1,256}\.[a-zA-Z0-9()]{1,6}\b([-a-zA-Z0-9()@:%_+.~#?&//=]*)/;

export const getSchema = (t: TFunction<'organizationApplication', 'supportProfile'>) =>
  yup.object().shape({
    city: yup.string().required(),
    country: yup.string().required(),
    email: yup.string().required(),
    line1: yup.string().required(),
    line2: yup.string(),
    phone: yup.string().required(),
    postalCode: yup.string().required(),
    region: yup.string().required(),
    social: yup
      .array()
      .of(
        yup.object({
          provider: yup.string().required(t('socialProfiles.required.profileType')),
          url: yup
            .string()
            .trim()
            .test('is-valid-https-url', t('socialProfiles.required.url'), (value) => {
              if (!value) {
                return true;
              }

              return HTTPS_URL_REGEX.test(value);
            })
            .nullable()
            .notRequired(),
        })
      )
      .required(),
    softDescriptor: yup.string().required(t('softDescriptor.required')),
  });

